    /* =====================================================================
     * Viewport clamping — the dropdown must stay on screen near the edges
     *
     * `openMenu(x, y)` positions the `position: fixed` `.row-menu` at the raw
     * viewport coordinates. When the menu is opened (right-click near the
     * right/bottom edge, or the ⋮ button when the row sits at the bottom) the
     * 140px-min-width menu would otherwise overflow off-screen, get clipped,
     * and/or introduce scrollbars — making action items partially/fully
     * unclickable. The coords must be clamped so the menu's left/top never
     * drop below 4px and the right/bottom edge never exceeds
     * innerWidth/innerHeight minus a 4px margin.
     *
     * These tests drive the menu via right-click (which lets us specify exact
     * clientX/clientY) and via the ⋮ button. They compute the expected clamp
     * from the menu's OWN measured size + the viewport, so they stay valid
     * whether the layout engine reports a real size or (as happy-dom does) 0.
     * ===================================================================== */
    describe('viewport clamping (overflow near edges)', () => {
      /** Expected clamped left for a requested x, using the menu's measured width. */
      function expectedClampX(menu: HTMLElement, x: number): number {
        const maxX = window.innerWidth - menu.getBoundingClientRect().width - 4;
        return Math.max(4, Math.min(x, maxX));
      }
      /** Expected clamped top for a requested y, using the menu's measured height. */
      function expectedClampY(menu: HTMLElement, y: number): number {
        const maxY = window.innerHeight - menu.getBoundingClientRect().height - 4;
        return Math.max(4, Math.min(y, maxY));
      }
      /** Parse a "Npx" style value to a number (NaN if unset). */
      function px(styleValue: string): number {
        return parseFloat(styleValue);
      }
      /** Open the row's menu at (x, y) by dispatching a right-click on the row. */
      function openViaContext(row: Element, x: number, y: number): void {
        row.dispatchEvent(
          new MouseEvent('contextmenu', {
            cancelable: true,
            bubbles: true,
            clientX: x,
            clientY: y,
          }),
        );
      }

      it('leaves coordinates unchanged when opened well inside the viewport (clamp is a no-op)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
        const menu = menuOf(actionsOf(results, 'a.txt'));

        openViaContext(row, 137, 242);

        // Within bounds → raw coordinates are used verbatim.
        expect(px(menu.style.left)).toBe(137);
        expect(px(menu.style.top)).toBe(242);
        // And they coincide with the clamp formula (a no-op here).
        expect(px(menu.style.left)).toBe(expectedClampX(menu, 137));
        expect(px(menu.style.top)).toBe(expectedClampY(menu, 242));
      });

      it('clamps left/top down when right-clicked past the bottom-right corner', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
        const menu = menuOf(actionsOf(results, 'a.txt'));

        // Far beyond the viewport — would overflow off-screen without clamping.
        openViaContext(row, 99999, 99999);

        const left = px(menu.style.left);
        const top = px(menu.style.top);
        const rect = menu.getBoundingClientRect();

        // The raw coords were NOT used verbatim.
        expect(left).toBeLessThan(99999);
        expect(top).toBeLessThan(99999);
        // Clamped exactly to the largest x/y that keeps the menu inside, with a
        // 4px right/bottom margin (width/height subtracted so the far edge fits).
        expect(left).toBe(window.innerWidth - rect.width - 4);
        expect(top).toBe(window.innerHeight - rect.height - 4);
        expect(left).toBe(expectedClampX(menu, 99999));
        expect(top).toBe(expectedClampY(menu, 99999));
        // Menu box stays entirely within the viewport.
        expect(left).toBeGreaterThanOrEqual(4);
        expect(top).toBeGreaterThanOrEqual(4);
        expect(left + rect.width).toBeLessThanOrEqual(window.innerWidth);
        expect(top + rect.height).toBeLessThanOrEqual(window.innerHeight);
