        expect(px(menu.style.top)).toBe(4);
        expect(px(menu.style.left)).toBe(expectedClampX(menu, -500));
        expect(px(menu.style.top)).toBe(expectedClampY(menu, -500));
      });

      it('clamps only the overflowing axis: x past the right edge, y within bounds', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));
        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
