describe('src/app.css — row action "⋮" button (.row-menu-btn)', () => {
  it('is a chromeless, muted, clickable button with compact sizing', () => {
    const btn = ruleDeclarations(/\.row-menu-btn/);
    expect(btn, 'a base .row-menu-btn { ... } rule must exist').not.toBeNull();
    expect(/background\s*:\s*none/.test(btn!), 'background:none').toBe(true);
    expect(/border\s*:\s*none/.test(btn!), 'border:none').toBe(true);
    expect(/color\s*:\s*#9a9a9a/.test(btn!), 'muted foreground #9a9a9a').toBe(true);
    expect(/cursor\s*:\s*pointer/.test(btn!), 'cursor:pointer').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(btn!), 'border-radius:4px').toBe(true);
    expect(/font-size\s*:\s*16px/.test(btn!), 'font-size:16px').toBe(true);
    expect(/line-height\s*:\s*1/.test(btn!), 'line-height:1').toBe(true);
    // modest padding (e.g. 2px 6px); assert it is present and pixel-based.
    expect(/padding\s*:\s*\d+px/.test(btn!), 'padding present').toBe(true);
  });

  it('is initially suppressed (low opacity, non-interactive) by default', () => {
    // The base rule keeps the trigger quiet until the row is hovered/focused or
    // its menu is open: `pointer-events:none` stops it capturing clicks while
    // idle, and the opacity is driven to a LOW (0 or faint) value. The exact
    // idle opacity is implementation-defined (see the touch-reachability test
    // below) — it may stay 0 (hidden, revealed only by interaction) or be lifted
    // to a faint non-zero value so touch users can perceive it — but it must NOT
    // be fully opaque at rest.
    const btn = ruleDeclarations(/\.row-menu-btn/)!;
    expect(/pointer-events\s*:\s*none/.test(btn), 'pointer-events:none by default').toBe(true);
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'base opacity suppresses visibility (< 1) at rest').toBeLessThan(1);
  });

  it('becomes visible + interactive on row hover and when its menu is open', () => {
    // The grouped reveal rule covers both conditions; anchor on the
    // [aria-expanded="true"] selector which is the last one before the brace.
    const reveal = ruleDeclarations(/\.row-menu-btn\[aria-expanded=['"]true['"]\]/);
    expect(reveal, 'a reveal rule covering [aria-expanded="true"] must exist').not.toBeNull();
    expect(/opacity\s*:\s*1/.test(reveal!), 'revealed opacity:1').toBe(true);
    expect(/pointer-events\s*:\s*auto/.test(reveal!), 'revealed pointer-events:auto').toBe(true);
    // Row-hover must also be one of the reveal selectors.
    expect(CSS, 'hover reveal must include the browse row-hover selector').toContain(
      '.browse-table tbody tr:hover .row-menu-btn',
    );
  });

  it('brightens to full foreground on its own hover', () => {
    const hover = ruleDeclarations(/\.row-menu-btn:hover/);
    expect(hover, 'a .row-menu-btn:hover rule must exist').not.toBeNull();
    expect(/color\s*:\s*#e6e6e6/.test(hover!), 'hover color #e6e6e6').toBe(true);
  });

  /* ── Accessibility fix: keyboard focus & touch reachability ──
     The trigger was opacity:0 + pointer-events:none by default and revealed
     ONLY by `tr:hover` / `[aria-expanded="true"]`. That left it (1) with NO
     visible focus indicator for keyboard users (WCAG 2.4.7 / 2.1.1) and (2)
     completely unreachable on touch devices, which have no :hover (WCAG
     2.5.1 / 2.5.8). The tests below pin the CSS contract that fixes both. */
  it('becomes visible + interactive on keyboard focus, not only on hover/open', () => {
    // The reveal rule (opacity:1 + pointer-events:auto) must include a
    // keyboard-focus selector — :focus-visible on the button and/or
    // :focus-within on the row — so a keyboard user sees & can operate it.
    const selectors = revealSelectorList();
    expect(
      selectors.length,
      'a reveal rule (opacity:1 + pointer-events:auto) must exist',
    ).toBeGreaterThan(0);
    const hasFocusReveal =
      selectors.includes('.row-menu-btn:focus-visible') || selectors.includes('tr:focus-within');
    expect(
      hasFocusReveal,
      'the reveal rule must include a keyboard-focus selector ' +
        '(.row-menu-btn:focus-visible and/or .browse-table tbody tr:focus-within .row-menu-btn) ' +
        'so keyboard users see & can operate the trigger',
    ).toBe(true);
  });

  it('shows a visible focus ring on keyboard focus (.row-menu-btn:focus-visible)', () => {
    // A keyboard user tabbing to the trigger must see where focus landed. The
    // grouped reveal selector `.row-menu-btn:focus-visible,` ends in a comma, so
    // ruleDeclarations (which requires the selector to sit immediately before
    // `{`) matches only the STANDALONE focus-ring rule, not the grouped reveal.
    const ring = ruleDeclarations(/\.row-menu-btn:focus-visible/);
    expect(
      ring,
      'a .row-menu-btn:focus-visible { ... } rule must exist to draw a focus ring',
    ).not.toBeNull();
    expect(
      /outline\s*:\s*(?!none\b)/.test(ring!),
      ':focus-visible must set a visible outline (not outline:none)',
    ).toBe(true);
    expect(
      /outline-offset\s*:/.test(ring!),
      ':focus-visible should set outline-offset so the ring clears the button box',
    ).toBe(true);
  });

  it('is reachable on touch devices (no :hover): faintly visible by default OR a @media (hover:none) reveal', () => {
    // Touch devices have no :hover, so the hover-based reveal never fires and
    // the whole row-actions feature would be unreachable. The trigger must be
    // perceivable & operable without a hover-capable pointer. Either of these
    // satisfies the contract:
    //   (a) a faint-but-non-zero base opacity (button at least visible at rest), or
    //   (b) a @media (hover: none) block that reveals the button
    //       (opacity + pointer-events:auto) on hover-incapable devices.
    const base = ruleDeclarations(/\.row-menu-btn/)!;
    const op = base.match(/opacity\s*:\s*([0-9.]+)/);
    const faintlyVisibleByDefault = !!op && Number(op[1]) > 0;

    const mediaBody = mediaHoverNoneBody();
    const mediaRevealsOnTouch =
      /\.row-menu-btn/.test(mediaBody) &&
      /opacity\s*:/.test(mediaBody) &&
      /pointer-events\s*:\s*auto/.test(mediaBody);

    expect(
      faintlyVisibleByDefault || mediaRevealsOnTouch,
      'on touch (no :hover) the trigger must be perceivable & operable: either a ' +
        'non-zero base opacity OR a @media (hover:none) reveal of the button',
    ).toBe(true);
  });
});

/* ===========================================================================
 * Row menu "⋮" trigger — hit-area / target SIZE (WCAG 2.5.8 Target Size Minimum)
 *
 * Even once the trigger is made perceivable & operable (the focus/touch fixes
 * covered above), its tappable box must be large enough to hit accurately. The
 * base rule historically rendered at ~20px tall × ~28px wide (padding 2px 6px,
 * font-size 16px, line-height 1), which is BELOW the WCAG 2.5.8 (AA) 24×24 CSS-px
 * minimum target size — and well below the 2.5.5 (AAA) / platform 44×44 guidance.
 * For a hover-gated trigger this is doubly punishing on touch, so the hit area
 * is enlarged to >= 24×24 (preferably ~32px) by raising the padding and adding
 * explicit min-width / min-height, WITHOUT changing the glyph's visual size
 * (font-size/line-height stay 16px / 1) and without regressing the chromeless
 * look or the opacity/pointer-events reveal behavior.
 *
 * As throughout this file the raw stylesheet is parsed (the vitest env does not
 * load app.css, so getComputedStyle cannot observe author rules). We read the
 * numeric min-width / min-height and compute the rendered box height from
 * font-size × line-height + vertical padding, asserting each axis >= 24px.
 * ========================================================================= */
describe('src/app.css — "⋮" trigger hit area meets WCAG 2.5.8 minimum (>= 24×24)', () => {
  const WCAG_AA_MIN = 24; // CSS px, WCAG 2.5.8 (AA) Target Size Minimum

  /**
   * Read the value (in px) of a `prop: <n>px` declaration on a rule block.
   * Anchored on a preceding start-of-block or `;` so a prop name cannot match a
   * suffix of another property (e.g. `min-width` will never match `max-width`).
   * Returns null when the property is absent.
   */
  function pxValue(decls: string, prop: string): number | null {
    const re = new RegExp(`(?:^|;)\\s*${prop}\\s*:\\s*([0-9]+)px`, 'm');
    const m = decls.match(re);
    return m ? Number(m[1]) : null;
  }

  /** First (vertical) value of a `padding: <v>px [<h>px]?` declaration. */
  function verticalPaddingPx(decls: string): number {
    const m = decls.match(/padding\s*:\s*([0-9]+)px(?:\s+[0-9]+px)?/);
    return m ? Number(m[1]) : 0;
  }

  let btn: string;
  beforeAll(() => {
    btn = ruleDeclarations(/\.row-menu-btn/)!;
    expect(btn, 'a base .row-menu-btn { ... } rule must exist').not.toBeNull();
  });

  it('declares a min-width >= 24px so the box is never narrower than the minimum', () => {
    const mw = pxValue(btn, 'min-width');
    expect(mw, '.row-menu-btn must declare a px min-width (floor on tap width)').not.toBeNull();
    expect(mw!, 'min-width must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('declares a min-height >= 24px so the box is never shorter than the minimum', () => {
    const mh = pxValue(btn, 'min-height');
    expect(mh, '.row-menu-btn must declare a px min-height (floor on tap height)').not.toBeNull();
    expect(mh!, 'min-height must be >= 24px (WCAG 2.5.8 AA)').toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('renders a box >= 24px tall from font-size × line-height + vertical padding', () => {
    // The trigger's content height is line-height(1) × font-size, grown by the
    // vertical padding; the box height is the max of that and min-height. This
    // pins the EFFECTIVE hit height regardless of which mechanism delivers it.
    const fontSize = pxValue(btn, 'font-size') ?? 0;
    const lh = btn.match(/line-height\s*:\s*([0-9.]+)/);
    const lineHeight = lh ? Number(lh[1]) : 1; // unitless multiplier; default 1
    const minH = pxValue(btn, 'min-height') ?? 0;
    const boxHeight = Math.max(fontSize * lineHeight + verticalPaddingPx(btn) * 2, minH);
    expect(
      boxHeight,
      `rendered hit-box height must be >= 24px (got ${boxHeight}px from font-size ${fontSize}px, ` +
        `line-height ${lineHeight}, padding ${verticalPaddingPx(btn)}px, min-height ${minH}px)`,
    ).toBeGreaterThanOrEqual(WCAG_AA_MIN);
  });

  it('keeps the visual glyph size unchanged while enlarging the target', () => {
    // The hit-area fix must NOT change the glyph itself: font-size stays 16px
    // and line-height stays 1.
    expect(pxValue(btn, 'font-size'), 'font-size stays 16px (glyph not resized)').toBe(16);
    expect(btn, 'line-height stays 1').toMatch(/line-height\s*:\s*1\s*;/);
  });

  it('preserves the chromeless look and idle reveal behavior after enlarging', () => {
    // The size change must not regress the other base-rule contracts.
    expect(/background\s*:\s*none/.test(btn), 'background:none preserved').toBe(true);
    expect(/border\s*:\s*none/.test(btn), 'border:none preserved').toBe(true);
    expect(/border-radius\s*:\s*4px/.test(btn), 'border-radius:4px preserved').toBe(true);
    expect(/cursor\s*:\s*pointer/.test(btn), 'cursor:pointer preserved').toBe(true);
    expect(/pointer-events\s*:\s*none/.test(btn), 'pointer-events:none at rest preserved').toBe(
      true,
    );
    const op = btn.match(/opacity\s*:\s*([0-9.]+)/);
    expect(op, 'opacity declared on the base rule').not.toBeNull();
    expect(Number(op![1]), 'opacity stays suppressed (<1) at rest').toBeLessThan(1);
  });
});

